def factorial(n: int) -> int {
    result: int = 1;
    i: int = 2;
    while i <= n {
        result = result * i;
        i = i + 1;
    }
    return result;
}

with entry {
    value: int = 6;
    print(factorial(value));
}

def sum_positive(values: list[int]) -> int {
    total: int = 0;
    for item in values {
        if item > 0 {
            total = total + item;
        }
    }
    return total;
}

with entry {
    readings: list[int] = [12, -4, 7, 0, -2, 9];
    print(sum_positive(readings));
}

